('visual-impairment-built-environment', 'VIB-07', NULL, NULL, 1, 0, '[]', 'Hankookilbo news article fetched and fully read: interview-based journalism naming the Korean Federation of the Visually Impaired''s facility-support center, Seoul Metro, and a 1998 statutory regulation, but no academic studies. NULL RESULT — attempted and complete.', '2026-07-19T23:46:41Z', 'session_2026-07-19-citation-mining-nonenglish-batch1', '2026-07-20T00:38:19Z', 'session_2026-07-19-citation-mining-nonenglish-batch6-redo', NULL),
('accessible-design-economics-cost-premium', 'ECP-02', NULL, NULL, 1, 0, '["CCD-12"]', 'Backward mining not applicable: source is an organisation homepage, product/catalog page, news article, or standards-catalog listing with no citable bibliography/reference list of its own (verified by fetching the URL). Forward mining: no DOI/PMID and no citation-graph connector for this non-indexed grey-literature source. DEFERRED, both directions.', '2026-07-19T23:46:41Z', 'session_2026-07-19-citation-mining-nonenglish-batch1', '2026-07-20 00:30', 'session_2026-07-19-citation-mining-nonenglish-batch5-browse', 'non_dob_grey_lit'),
('manoeuvring-footprint-vs-turning-radius-methodology', 'MFM-01', NULL, '10.3389/fspor.2023.1127514', 1, 1, '["MFM-09", "MFM-10", "MFM-11", "MFM-12", "MFM-13", "MFM-14", "MFM-15", "MFM-16", "MFM-17", "MFM-18", "MFM-19", "MFM-20", "MFM-21", "MFM-22", "MFM-23", "MFM-24", "MFM-25", "MFM-26", "MFM-27", "MFM-28", "MFM-29", "MFM-30"]', 'Forward mining completed via Semantic Scholar Graph API (api.semanticscholar.org /graph/v1/paper/DOI:.../citations) — a genuine citation-graph ''cited by'' endpoint, not topical search. Supersedes the earlier deferred_reason logged against Scholar Gateway (which lacks a real citation graph). Candidates filtered for built-environment/disability-population relevance per skill §3, verified via the API''s own DOI/PMID metadata, deduped against the existing evidence base before insert.', '2026-07-19 23:43', 'session_2026-07-19-citation-mining-nonenglish-batch1', '2026-07-19T23:57:16Z', 'session_2026-07-19-citation-mining-nonenglish-batch2-forward', NULL),
('deafblind-built-environment-design', 'DBL-07', NULL, NULL, 1, 0, '[]', 'dinf.ne.jp page fetched and fully read: names only Helen Keller (historical reference to fingerspelling method), and links to an internal ''Reference Material 1'' page not followed up this pass. NULL RESULT for formal citations; the internal reference-material link remains an unpursued lead.', '2026-07-19T23:46:41Z', 'session_2026-07-19-citation-mining-nonenglish-batch1', '2026-07-20T00:38:19Z', 'session_2026-07-19-citation-mining-nonenglish-batch6-redo', NULL),
('deafblind-built-environment-design', 'DBL-09', NULL, NULL, 1, 0, '[]', 'Same source document as DBL-07 (identical URL) — same finding applies.', '2026-07-19T23:46:41Z', 'session_2026-07-19-citation-mining-nonenglish-batch1', '2026-07-20T00:38:19Z', 'session_2026-07-19-citation-mining-nonenglish-batch6-redo', NULL),
('deaf-spatial-design', 'DSD-10', NULL, NULL, 0, 0, '[]', 'Gazzetta Ufficiale page fetched: only law metadata visible, not full text. ''Lavori Preparatori'' (preparatory materials) are linked separately but not fetched this pass. DEFERRED, not null — preparatory materials specifically not yet checked.', '2026-07-19T23:46:41Z', 'session_2026-07-19-citation-mining-nonenglish-batch1', '2026-07-20T00:38:19Z', 'session_2026-07-19-citation-mining-nonenglish-batch6-redo', 'site_specific_lead_unresolved'),
